package main

import (
    "fmt"
    "net/http"
)

func main() {
    // Define the URL you want to make a request to
    url := "http://example.com"

    // Create a new GET request to the specified URL
    resp, err := http.Get(url)
    if err != nil {
        fmt.Println("Error making request:", err)
        return
    }
    defer resp.Body.Close()

    // Read the response body
    body, err := readBody(resp.Body)
    if err != nil {
        fmt.Println("Error reading response body:", err)
        return
    }

    // Print the content of the response body
    fmt.Println("Response Content:")
    fmt.Println(body)
}

// Helper function to read the body of the response
func readBody(r io.Reader) (string, error) {
    scanner := bufio.NewScanner(r)
    var body strings.Builder

    for scanner.Scan() {
        body.WriteString(scanner.Text())
        body.WriteString("\n") // Add a newline for readability
    }

    if err := scanner.Err(); err != nil {
        return "", err
    }

    return body.String(), nil
}
```

This Go code snippet demonstrates how to make a GET request to a specified URL and print the content of the response. The `readBody` function reads the response body line by line and accumulates the content, which is then printed out.

